const intake = $json.intake_result || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const manifestPathAbs = toContainerPath(intake.manifest_path);
const captionResultPathAbs = manifestPathAbs ? manifestPathAbs.replace(/manifest\.json$/, 'caption_result.json') : null;

return {
  json: {
    job_id: intake.job_id || null,
    manifest_path: manifestPathAbs,
    caption_result_path: captionResultPathAbs,
    intake_status: intake.status || null,
    platform_targets: intake.platform_targets || [],
    clip_path: intake.clip_path || null,
    eligible_for_caption: intake.status === 'ASSETS_VALID' && Boolean(manifestPathAbs) && Boolean(captionResultPathAbs),
    intake_result: intake
  }
};

const manifest = $json.manifest || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

return {
  json: {
    ...$json,
    manifest,
    source_video_url: manifest.source_video_url || null,
    source_video_id: manifest.source_video_id || null,
    source_video_title: manifest.source_video_title || null,
    source_video_uploader: manifest.source_video_uploader || null,
    source_video_duration: manifest.source_video_duration || null,
    source_video_description: manifest.source_video_description || null,
    approval_mode: manifest.approval_mode || 'required',
    platform_targets: Array.isArray(manifest.platform_targets) && manifest.platform_targets.length > 0 ? manifest.platform_targets : ($json.platform_targets || []),
    transcript_path_abs: toContainerPath(manifest.transcript_path),
    thumbnail_path_abs: toContainerPath(manifest.thumbnail_path),
    clip_path_abs: toContainerPath(manifest.clip_path),
    clip_count: manifest.clip_count || (Array.isArray(manifest.clips) ? manifest.clips.length : 0)
  }
};

const binaryAvailable = Boolean($binary && Object.keys($binary).length > 0);
return {
  json: {
    ...$json,
    transcript_binary_available: binaryAvailable
  },
  binary: $binary
};

const defaults = {
  openai_caption_model: 'gpt-5.4-mini',
  openai_caption_language: 'id',
  openai_caption_brand_voice: 'ringkas, tajam, natural, tidak clickbait murahan',
  openai_caption_max_hashtags: '8'
};

let config = {};
let configError = null;
const binaryFieldName = $binary ? Object.keys($binary)[0] : null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const parsed = JSON.parse(rawBuffer.toString('utf8'));
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      config = parsed;
    } else {
      configError = 'Isi /files/config/caption_ai.json harus berupa object JSON.';
    }
  } catch (error) {
    configError = 'Config caption AI lokal tidak valid: ' + (error.message || 'parse gagal');
  }
}

return {
  json: {
    ...$json,
    caption_config_path: '/files/config/caption_ai.json',
    caption_config_error: configError,
    openai_api_key: String(config.openai_api_key || '').trim(),
    openai_caption_model: String(config.openai_caption_model || defaults.openai_caption_model),
    openai_caption_language: String(config.openai_caption_language || defaults.openai_caption_language),
    openai_caption_brand_voice: String(config.openai_caption_brand_voice || defaults.openai_caption_brand_voice),
    openai_caption_max_hashtags: String(config.openai_caption_max_hashtags || defaults.openai_caption_max_hashtags)
  }
};

const apiKey = String($json.openai_api_key || '').trim();
const model = String($json.openai_caption_model || 'gpt-5.4-mini');
const language = String($json.openai_caption_language || 'id');
const brandVoice = String($json.openai_caption_brand_voice || 'ringkas, tajam, natural, spesifik, tidak clickbait murahan');
const maxHashtags = Number.parseInt(String($json.openai_caption_max_hashtags || '8'), 10);
const transcriptText = String($json.transcript_text || '').trim();
const transcriptAvailable = transcriptText.length > 0;
const platformTargets = Array.isArray($json.platform_targets) ? $json.platform_targets : [];
const sourceTitle = String($json.source_video_title || '').trim();
const sourceUploader = String($json.source_video_uploader || '').trim();
const sourceDescription = String($json.source_video_description || '').trim();

function buildFailure(message) {
  return {
    json: {
      ...$json,
      transcript_available: transcriptAvailable,
      caption_generation_status: 'failed',
      caption_error: message,
      caption_model: model
    }
  };
}

const configError = String($json.caption_config_error || '').trim();
if (configError) {
  return buildFailure(configError);
}

if (!apiKey) {
  return buildFailure('Konfigurasi OpenAI belum tersedia di /files/config/caption_ai.json atau openai_api_key kosong.');
}

const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    content_angle: { type: 'string' },
    hashtags: {
      type: 'array',
      items: { type: 'string' }
    },
    caption_pack: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          platform: {
            type: 'string',
            enum: ['youtube_shorts', 'tiktok', 'facebook_reels']
          },
          caption: { type: 'string' },
          hashtags: {
            type: 'array',
            items: { type: 'string' }
          }
        },
        required: ['platform', 'caption', 'hashtags']
      }
    }
  },
  required: ['content_angle', 'hashtags', 'caption_pack']
};

const promptPayload = {
  language,
  brand_voice: brandVoice,
  max_hashtags: Number.isFinite(maxHashtags) ? maxHashtags : 8,
  platform_targets: platformTargets,
  approval_mode: $json.approval_mode || 'required',
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  source_video_title: sourceTitle || null,
  source_video_uploader: sourceUploader || null,
  source_video_duration: $json.source_video_duration || null,
  source_video_description: sourceDescription ? sourceDescription.slice(0, 3000) : null,
  clip_count: $json.clip_count || 1,
  transcript_available: transcriptAvailable,
  transcript_text: transcriptAvailable ? transcriptText.slice(0, 12000) : null
};

const body = {
  model,
  store: false,
  input: [
    {
      role: 'system',
      content: [
        {
          type: 'input_text',
          text: 'Anda adalah copywriter short-form content untuk creator automation. Balas hanya dengan JSON valid. Gunakan bahasa yang diminta. Fokus pada caption yang relevan dengan isi clip, terasa natural, dan tidak generik. Jangan keluarkan title, jangan keluarkan CTA, jangan keluarkan hook options. Jika transcript tersedia, ambil detail dari transcript. Jika transcript tidak tersedia, gunakan source_video_title, source_video_uploader, dan source_video_description sebagai konteks utama. Jangan keluarkan fallback generik seperti potongan clip singkat atau langsung ke inti kecuali konteks memang benar-benar minim. Jangan mengarang klaim faktual yang tidak didukung transcript atau metadata sumber.'
        }
      ]
    },
    {
      role: 'user',
      content: [
        {
          type: 'input_text',
          text: JSON.stringify(promptPayload, null, 2)
        }
      ]
    }
  ],
  text: {
    format: {
      type: 'json_schema',
      name: 'caption_result',
      strict: true,
      schema
    }
  }
};

try {
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/responses',
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + apiKey
    },
    body,
    json: true,
  });

  let parsed = data.output_parsed || null;
  let outputText = data.output_text || '';

  if (!parsed) {
    if (!outputText && Array.isArray(data.output)) {
      for (const item of data.output) {
        if (!Array.isArray(item.content)) continue;
        for (const part of item.content) {
          if (typeof part.text === 'string' && part.text.trim()) {
            outputText = part.text;
            break;
          }
        }
        if (outputText) break;
      }
    }

    if (!outputText) {
      return buildFailure('OpenAI tidak mengembalikan output_text yang bisa diparse.');
    }

    parsed = JSON.parse(outputText);
  }

  return {
    json: {
      ...$json,
      transcript_available: transcriptAvailable,
      caption_generation_status: 'generated',
      caption_model: model,
      caption_ai_result: parsed
    }
  };
} catch (error) {
  const responseBody = error?.response?.body;
  const responseText = typeof responseBody === 'string'
    ? responseBody
    : responseBody
      ? JSON.stringify(responseBody).slice(0, 800)
      : '';
  const suffix = responseText ? ' :: ' + responseText : '';
  return buildFailure((error.message || 'Gagal memanggil OpenAI Responses API.') + suffix);
}

const generatedAt = new Date().toISOString();
const ai = $json.caption_ai_result || {};
const result = {
  job_id: $json.job_id || null,
  stage: 'WF-02_GENERATE_CAPTION',
  status: 'CAPTION_GENERATED',
  generated_at: generatedAt,
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  source_video_title: $json.source_video_title || null,
  source_video_uploader: $json.source_video_uploader || null,
  platform_targets: $json.platform_targets || [],
  approval_mode: $json.approval_mode || 'required',
  model: $json.caption_model || null,
  transcript_available: Boolean($json.transcript_available),
  content_angle: ai.content_angle || null,
  hashtags: ai.hashtags || [],
  caption_pack: ai.caption_pack || [],
  next_stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS'
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    caption_result_status: result.status,
    caption_result_payload: result
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'caption_result.json'
    }
  }
};

const generatedAt = new Date().toISOString();
const result = {
  job_id: $json.job_id || null,
  stage: 'WF-02_GENERATE_CAPTION',
  status: 'CAPTION_FAILED',
  generated_at: generatedAt,
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  platform_targets: $json.platform_targets || [],
  approval_mode: $json.approval_mode || 'required',
  model: $json.caption_model || null,
  transcript_available: Boolean($json.transcript_available),
  error_message: $json.caption_error || 'Caption generation gagal tanpa detail.',
  next_stage: null
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    caption_result_status: result.status,
    caption_result_payload: result
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'caption_result.json'
    }
  }
};
